// ============================================================================
// Catálogo de instruções de IA — registro único de TODAS as tarefas que usam
// LLM. Dirige a aba "IA — Contexto & Regras" (lista + edição de override) e o
// `applies_to` das Skills. O `default` aqui é a FONTE DE VERDADE versionada do
// system instruction de cada tarefa: buildSystemInstruction resolve
// override(app_settings) ?? default(catálogo) ?? fallback(call site). Como toda
// entrada tem `default`, é ELE que roda em produção (a menos que o admin defina
// um override). Os defaults abaixo são prompts de CSM sênior B2B enterprise e
// preservam EXATAMENTE o contrato de saída que cada call site parseia.
// ============================================================================

export interface AIInstructionDef {
  key: string
  label: string
  domain: string
  triggerType: 'user' | 'auto'
  /** default visível na UI e efetivo em runtime (system instruction da tarefa) */
  default?: string
  /** reservado: tarefas em planejamento (hoje nenhuma — catálogo só com IA em uso) */
  status?: 'active' | 'planned'
}

